                            const carousels = document.querySelectorAll('.carousel');
                            const itemWidth = 200; // Largeur de chaque élément

                            carousels.forEach(carousel => {
                                const items = carousel.querySelectorAll('.carousel-item');
                                const totalItems = items.length;
                                let index = 0; // Index actif

                                // Fonction pour déplacer le carousel
                                function moveToItem(carousel, index) {
                                    carousel.style.transition = 'transform 0.5s ease-in-out';
                                    carousel.style.transform = `translateX(-${index * itemWidth}px)`;
                                }

                                window.moveLeft = function (carouselId) {
                                    const carousel = document.getElementById(carouselId);
                                    const items = carousel.querySelectorAll('.carousel-item');
                                    const totalItems = items.length;
                                    index = (index > 0) ? index - 1 : totalItems - 1;
                                    moveToItem(carousel, index);
                                }

                                window.moveRight = function (carouselId) {
                                    const carousel = document.getElementById(carouselId);
                                    const items = carousel.querySelectorAll('.carousel-item');
                                    const totalItems = items.length;
                                    index = (index + 1) % totalItems;
                                    moveToItem(carousel, index);
